import org.eclipse.jdt.core.dom.IMethodBinding;
import java.lang.reflect.Modifier;

class QuickAssistProcessor {
    void processMethod(IMethodBinding referredMethodBinding) {
        // Before (part of an else if condition)
        if (false) {} else if (Modifier.isStatic(referredMethodBinding.getModifiers()) && !referredMethodBinding.isSynthetic()) {
            System.out.println("Condition matched: static and not synthetic");
        }
    }
}

